/**
 *  \u624B\u5199\u7528 ES6proxy \u5982\u4F55\u5B9E\u73B0 arr[-1] \u7684\u8BBF\u95EE
 */

const arrProxy = (arr) =>
  new Proxy(arr, {
    get(target, key) {
      key = +key;
      while (key < 0) {
        key += target.length;
      }
      return target[key];
    },
  });

const a = arrProxy([0, 1, 2, 3]);
console.log(a);
