import { Button } from 'antd';
export default () => {
  let event = new Event('XX', { cancelable: false, bubbles: true });
  addEventListener('XX', function () {
    console.log(1212);
  });
  return (
    <Button
      onClick={() => {
        document.dispatchEvent(event);
      }}
    >
      hello
    </Button>
  );
};

