var reg = /^[^0-9A-Za-z]$/; //^\u53CD\u4E49\u5B57\u7B26 \u53EA\u8981\u5305\u542B\u65B9\u62EC\u53F7\u5185\u7684\u5B57\u7B26\uFF0C\u90FD\u8FD4\u56DE false
console.log(reg.test('a')); //false
console.log(reg.test('A')); //false
console.log(reg.test('2')); //false
console.log(reg.test('!')); //true
