console.log(RegExp.$4); //fruit

// \u5F15\u7528\uFF1A \u6B63\u5219\u8868\u8FBE\u5F0F\u91CC\u4E5F\u80FD\u8FDB\u884C\u5F15\u7528\uFF0C\u8FD9\u79F0\u4E3A\u53CD\u5411\u5F15\u7528
