console.log(reg.test('kid is dik')); // false
console.log(reg.test('dik is kid')); // false
//\\1\u5F15\u7528\u4E86\u7B2C\u4E00\u4E2A\u88AB\u5206\u7EC4\u6240\u6355\u83B7\u7684\u4E32\uFF0C\u6362\u8A00\u4E4B\uFF0C\u8868\u8FBE\u5F0F\u662F\u52A8\u6001\u51B3\u5B9A\u7684\u3002

