`,paraId:16,tocIndex:4},{value:"sharedWorker \u5728\u63A5\u6536\u5230\u6570\u636E\u540E\uFF0C\u6839\u636E\u6570\u636E\u7C7B\u578B\u5904\u7406 num \u8BA1\u6570\uFF0C\u7136\u540E\u8FD4\u56DE\u7ED9\u6BCF\u4E2A\u5DF2\u8FDE\u63A5\u7684\u4E3B\u7EBF\u7A0B\u3002",paraId:17,tocIndex:4},{value:`// sharedWorker.js

let num = 0;
const workerList = [];

self.addEventListener('connect', (e) => {
  const port = e.ports[0];
  port.addEventListener('message', (e) => {
    num += e.data === 'add' ? 1 : -1;
    workerList.forEach((port) => {
      // \u904D\u5386\u6240\u6709\u5DF2\u8FDE\u63A5\u7684part\uFF0C\u53D1\u9001\u6D88\u606F
      port.postMessage(num);
    });
  });
  port.start();
  workerList.push(port); // \u5B58\u50A8\u5DF2\u8FDE\u63A5\u7684part
  port.postMessage(num); // \u521D\u59CB\u5316
});
