function set(obj, keysString, value) {
  const keys = keysString.split('.');
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    obj[key] = i === keys.length - 1 ? value : obj[key] || {};
    obj = obj[key];
  }
  return obj;
}

let a = {};
set(a, 'params.name.age', '18');

console.log('a', a);
