// lib.js(CommonJS)
var counter = 3;
function incCounter() {
  counter++;
}
module.exports = {
  counter: counter,
  incCounter: incCounter,
};

// main.js
var mod = require('./lib');

console.log(mod.counter); // 3
mod.incCounter();
console.log(mod.counter); // 3

// ES Module
// m1.js(ES Module)
export var foo = 'bar';
setTimeout(() => (foo = 'baz'), 500);

// m2.js(ES Module)
import { foo } from './m1.js';
console.log(foo); // bar
setTimeout(() => console.log(foo), 500); //baz

// \u7531\u4E8E ES6 \u8F93\u5165\u7684\u6A21\u5757\u53D8\u91CF\uFF0C\u53EA\u662F\u4E00\u4E2A\u201C\u7B26\u53F7\u8FDE\u63A5\u201D\uFF0C\u6240\u4EE5\u8FD9\u4E2A\u53D8\u91CF\u662F\u53EA\u8BFB\u7684\uFF0C\u5BF9\u5B83\u8FDB\u884C\u91CD\u65B0\u8D4B\u503C\u4F1A\u62A5\u9519\u3002
// lib.js
export let obj = {};

// main.js
import { obj } from './lib';

obj.prop = 123; // OK
obj = {}; // TypeError
